&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%BF%AB%E6%8D%B7%E9%94%AE&#34;&gt;快捷键&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%95%B0%E6%8D%AE%E8%BF%81%E7%A7%BB&#34;&gt;数据迁移&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
