&lt;li&gt;&lt;a href=&#34;#%E9%94%AE%E7%9B%98&#34;&gt;键盘&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;通用&#34;&gt;通用&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;IDEA&lt;/code&gt; 与 &lt;code&gt;VScode&lt;/code&gt;与 &lt;code&gt;浏览器&lt;/code&gt;(某些部分) 通用性的非修改的快捷键&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;全屏&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;F11&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;关闭标签 // 后台打开链接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;中键&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;搜索 // 新建标签 // 关闭标签 // 保存&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + F // T // W(F4) // S&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;恢复刚关闭的标签&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + T&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;切换左右标签 // 转到第 N 编辑器块&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + PageUp/PageDown //~ / 1 / 2 / 3 ...&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;放大/缩小&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + +(=) / -(-)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;行//块注释&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + alt + A&lt;/code&gt;//&lt;code&gt;Ctrl + /&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;撤销 / 重做&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + Z&lt;/code&gt; / &lt;code&gt;Ctrl + shift + Z&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;查找(替换) / 全局查找(替换) / 文件内逐词遍历(方便)&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + F(H)&lt;/code&gt; / &lt;code&gt;Ctrl + shift + F(H)&lt;/code&gt; / &lt;code&gt;F3&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在多个列上添加光标 // 多个行尾添加光标&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + ↑ / ↓&lt;/code&gt;/&lt;code&gt;(中键)&lt;/code&gt; // &lt;code&gt;在行首添加完再转行尾&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;移动编辑器组&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + K + ←/↑/↓/→&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;把当前行上/下移 // 向下/上复制一行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + ↑ / ↓&lt;/code&gt; // &lt;code&gt;shift + alt + ↓ / ↑&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;格式化&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + alt + F&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳转&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl/alt + G&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向右拆分编辑器&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + \&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;功能键区&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + 小键盘数字&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;源代码操作(生成)&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + insert&lt;/code&gt; / &lt;code&gt;shift + alt + Num0&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速修复&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + \&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;修改的快捷键&#34;&gt;修改的快捷键&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上 / 下 / 左 / 右移&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Alt + I / K / J(U) / L(O)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;转到行首/尾 // 选中到行首/尾(不包含缩进)&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + N(home) / M(end)&lt;/code&gt; // &lt;code&gt;shift + Alt + N / M&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;换行//向上扩展行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + ,&lt;/code&gt; / &lt;code&gt;Ctrl + enter&lt;/code&gt; // &lt;code&gt;Ctrl + Shift + Enter&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + ;&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;VScode&#34;&gt;VScode&lt;/h2&gt;
&lt;h3 id=&#34;非修改键位-插件键位&#34;&gt;非修改键位/插件键位&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;选中当前行 / 返回上一个光标位置&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + L&lt;/code&gt; / &lt;code&gt;Ctrl + U&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;非调试运行/运行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;(Ctrl) + F5&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;收缩/扩展选择&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + alt + ←&lt;/code&gt; / &lt;code&gt;→&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;快速选择引号内容&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + A&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;资源管理器 / 项目管理器&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + E&lt;/code&gt; / &lt;code&gt;shift + alt + P&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;保持打开状态 / 固定标签&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + K &amp;amp;&amp;amp; Enter&lt;/code&gt; / &lt;code&gt;Ctrl + K &amp;amp;&amp;amp; shift + Enter&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;插入文件头 / 函数注释 / Code Runner&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl+ alt + I&lt;/code&gt; / &lt;code&gt;T&lt;/code&gt; / &lt;code&gt;N&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;开关侧边栏 / 开关 Console / 新建终端&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + B&lt;/code&gt; / &lt;code&gt;Ctrl + ~&lt;/code&gt; / &lt;code&gt;Ctrl + shift + ~&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​​​​​Quokka 运行 JS&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + K + Q&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;Find all Reference&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + F12&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上/下页跳转光标 // 视图上/下滚动(翻页)&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;PageUp / PageDown&lt;/code&gt; / &lt;code&gt;alt + ↑(PageUp) / ↓(PageDown)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;markdown 预览 / picgo 插入/粘贴图片 / 插入书签&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + Shift + V&lt;/code&gt; / &lt;code&gt;E/U&lt;/code&gt; / &lt;code&gt;K&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;匹配文本后面出现光标(贼重要) / 全文匹配文本逐一遍历选择(好用)&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + L&lt;/code&gt; / &lt;code&gt;Ctrl + D&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;Java 重构 // Debug&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + R&lt;/code&gt; // &lt;code&gt;Ctrl + alt + N&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;copilot 上一个/下一个&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + [ / ]&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + N&lt;/code&gt; + &lt;code&gt;Ctrl + R&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开之前的工作区&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/GVa4dr.png&#34; alt=&#34;tjT21PGqH5xQNwz&#34;&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;Mover-非修改-已弃用&#34;&gt;&lt;s&gt;Mover 非修改&lt;/s&gt;(已弃用)&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;剪切/复制/粘贴&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + X / C / V&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;跳行&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + 数字 + ↑ / ↓&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上下左右移动视图&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + E / D / S / F&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;h3 id=&#34;键位修改后&#34;&gt;键位修改后.&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;触发代码补全 /&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + I&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向左/右缩进 // 全折叠/全展开&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;(shift + tab) Ctrl + [ / ]&lt;/code&gt; // &lt;code&gt;Ctrl + shift + [ / ]&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;markdown 创建文章目录&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + &#39;&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开 Live Server / 关闭 Server&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + alt + [&lt;/code&gt; / &lt;code&gt;]&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;终止//最大化终端&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + . // /&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开 copilot&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + alt + Enter&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;JetBrains&#34;&gt;JetBrains&lt;/h2&gt;
&lt;h3 id=&#34;原生&#34;&gt;原生&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;引入变量(右键-&amp;gt;重构-&amp;gt;也可以)&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + V&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;生成代码&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + insert(shift + Num0)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;类图表&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + U&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;运行类&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + F10&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;上/下一个窗口&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + [&lt;/code&gt; / &lt;code&gt;]&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;继承-VScode-键位修改&#34;&gt;继承 VScode 键位修改&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;基本快捷键&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;VScode keyboard map&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;Mover&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;已手动适配&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;h3 id=&#34;智能补全&#34;&gt;智能补全&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;输入&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;补全&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;fori&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;for(int i = 0;i &amp;lt; ;i++){}&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;100.for&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;for(int i = 0;i &amp;lt; ;i++){}&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;数组对象 a.for&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;for (int i : a) {}&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;foreach&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;for(:){}&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;ifn&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;if(args == null)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;sout&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;System.out.println()&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;xxx.sout&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;System.out.println(xxx)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;st&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;String&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;main/psvm&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;public static void main(String[] args) {}&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;terminal&#34;&gt;terminal&lt;/h2&gt;
&lt;h2 id=&#34;common&#34;&gt;common&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;delete by word&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;ctrl + backspace&lt;/code&gt; / &lt;code&gt;ctrl + w&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;Git&#34;&gt;Git&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;提交+推送&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + Enter&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;Git 暂存&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + A&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;software&#34;&gt;software&lt;/h2&gt;
&lt;h3 id=&#34;浏览器&#34;&gt;浏览器&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;选中地址栏&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + D&lt;/code&gt; / &lt;code&gt;Ctrl + L&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;新建标签&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + T&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开下载管理器&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + X&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;刷新&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + R&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;添加收藏夹&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + D&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;下载管理器&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + J&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;开关 Dark Reader&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;shift + alt + D&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;后台跳转链接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + 左键&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;检查元素&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + C&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;QQ&#34;&gt;QQ&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开消息面板&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + Z&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;截图&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + alt + ScrLK&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;搜狗&#34;&gt;搜狗&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;暂无&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;问题&#34;&gt;问题&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;有时候会遇到上传配置失败的情况&lt;/p&gt;
&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/GVLIeo.png&#34; alt=&#34;20210206124107&#34; /&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;可能是系统设置了代理,比如 clash 会&lt;code&gt;开启代理&lt;/code&gt;,暂时关掉就好了.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;Windows&#34;&gt;Windows&lt;/h2&gt;
&lt;h3 id=&#34;基本&#34;&gt;基本&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;任务管理器&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;Ctrl + shift + Esc&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;h3 id=&#34;Windows-徽标键&#34;&gt;Windows 徽标键&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;emoji 输入面板&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + . / ;&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;最小化除了当前窗口的所有窗口//所有窗口&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + home // D&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;预览桌面&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + ,&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开我的电脑//运行//控制中心&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + E//R//A&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;window 语音听写&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + H(hear)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;锁屏&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + L(Lock)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;电脑基本信息&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + pausebreak&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;h3 id=&#34;触摸板&#34;&gt;触摸板&lt;/h3&gt;
&lt;h4 id=&#34;原配&#34;&gt;原配&lt;/h4&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;视频前进/后退&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;双指左/右拖&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/GVE8AY.png&#34; alt=&#34;ygIOkb9ur1cdpMe&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;修改后&#34;&gt;修改后&lt;/h4&gt;
  &lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/GVicLq.png&#34; alt=&#34;20201227104041&#34; /&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;Utools&#34;&gt;Utools&lt;/h2&gt;
&lt;h3 id=&#34;快捷键&#34;&gt;快捷键&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;快捷键&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + space&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;面板上下选择//快捷选择&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;alt + J/K&lt;/code&gt; // &lt;code&gt;alt + 1/2/3...&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;h3 id=&#34;数据迁移&#34;&gt;数据迁移&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;退出程序,把数据目录剪切过来,然后执行:&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mklink /d &lt;span class=&#34;string&#34;&gt;&amp;quot;C:\Users\29845\AppData\Roaming\uTools&amp;quot;&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;D:\Game\Scoop\persist\uTools&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;会生成一个映射文件夹.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;键盘&#34;&gt;键盘&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;狼蛛-收割者 Fn 功能键位&lt;/p&gt;
&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/GVF2ao.png&#34; alt=&#34;Fn功能键位&#34; /&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;!--
 * @Author: Weidows
 * @Date: 2020-05-27 19:28:49
 * @LastEditors: Weidows
 * @LastEditTime: 2023-04-20 18:22:13
 * @FilePath: \Blog-private\source\_posts\tools\vscode\插件.md
--&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%89%8D%E8%A8%80&#34;&gt;前言&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AE%9E%E7%94%A8%E6%8E%A8%E8%8D%90&#34;&gt;实用推荐&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%BE%8E%E5%8C%96%E6%8E%A8%E8%8D%90&#34;&gt;美化推荐&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E4%B8%BB%E9%A2%98&#34;&gt;主题&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AA%97%E5%8F%A3%E9%80%8F%E6%98%8E&#34;&gt;窗口透明&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%85%B6%E4%BB%96&#34;&gt;其他&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%A0%81%E5%AD%97%E6%8E%A8%E8%8D%90&#34;&gt;码字推荐&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E4%BB%A3%E7%A0%81%E8%A1%A5%E5%85%A8&#34;&gt;代码补全&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%85%B6%E4%BB%96-1&#34;&gt;其他&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%96%87%E7%AB%A0%E6%8E%A8%E8%8D%90&#34;&gt;文章推荐&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;前言&#34;&gt;前言&lt;/h2&gt;
&lt;p&gt;莅临此处的应该是都知道 &lt;a href=&#34;https://code.visualstudio.com&#34;&gt;&lt;strong&gt;VScode&lt;/strong&gt;&lt;/a&gt; 是怎样一个&lt;em&gt;编辑器&lt;/em&gt; 了,再此处附上&lt;a href=&#34;#%E4%BA%8C.%E5%AE%9E%E7%94%A8%E6%8E%A8%E8%8D%90&#34;&gt;实用&lt;/a&gt; &lt;a href=&#34;#%E4%B8%89.%E7%BE%8E%E5%8C%96%E6%8E%A8%E8%8D%90&#34;&gt;美化&lt;/a&gt; &lt;a href=&#34;#%E5%9B%9B.%E7%A0%81%E5%AD%97%E6%8E%A8%E8%8D%90&#34;&gt;码字&lt;/a&gt;的推荐,希望喜欢!&lt;/p&gt;
&lt;p&gt;更新至: &lt;code&gt;2021-2&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;实用推荐&#34;&gt;实用推荐&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;h3 id=&#34;Bookmarks&#34;&gt;Bookmarks&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;让侧边栏出来个书签按钮,功能和名字一样,就是可以在某个地方&lt;strong&gt;做一个可以起名字的书签&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;相对比有相似的插件&lt;em&gt;TODO Highlight&lt;/em&gt;和&lt;em&gt;Todo Tree&lt;/em&gt;,这两个是令写了 TODO 的地方高亮/被标记,由于标记不能起名字,所以个人更喜欢可标识性的 Bookmarks.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Code-Spelling-Checker&#34;&gt;Code Spelling Checker&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;这个插件就很有意思了,它可以&lt;strong&gt;检查文件中单词的拼写错误&lt;/strong&gt;,并可以&lt;strong&gt;提出修改方案&lt;/strong&gt;,写代码,写 md,甚至写 txt 等等都可以用到&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Code-Time&#34;&gt;Code Time&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;这个插件可以&lt;strong&gt;记录对文件操作的时间&lt;/strong&gt;(只是打开文件没有动的情况下不会计时),对个人而言可以统计学习码字时间,可以登录谷歌或 Github 进行同步&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Comment-Translate&#34;&gt;Comment Translate&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;个人最喜欢的综合性较强的&lt;strong&gt;翻译插件&lt;/strong&gt;,支持划词翻译,在注释上悬浮翻译,段落翻译…速度和质量很优秀&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Remote-SSH&#34;&gt;Remote - SSH&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;作用主要是&lt;strong&gt;ssh 远程连接&lt;/strong&gt;,可以让 VScode 管理远程机上的文件/代码…&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Bracket-Select&#34;&gt;Bracket Select&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;快速选择&lt;code&gt;括起来的内容&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;包括单引号,双引号,小括号,中括号,大括号…&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;CodeSnap&#34;&gt;CodeSnap&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;代码截图&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;file-size&#34;&gt;file-size&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;显示文件大小&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Image-Preview&#34;&gt;Image Preview&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;可以预览图片&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;美化推荐&#34;&gt;美化推荐&lt;/h2&gt;
&lt;h3 id=&#34;主题&#34;&gt;主题&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;h3 id=&#34;Weidows-Design-theme&#34;&gt;Weidows Design theme&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;当然是我自己做的最好看了!&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Shades-of-Purple&#34;&gt;Shades of Purple&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;看起来紫气东来的一个主题&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Tinacious-Design&#34;&gt;Tinacious Design&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;个人最喜欢的主题,只要是 RGB+Cyberpunk 风格吸引我&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Dracula&#34;&gt;Dracula&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;代码配色太好看了!&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;窗口透明&#34;&gt;窗口透明&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;h3 id=&#34;Glasslt-VSC&#34;&gt;Glasslt-VSC&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;让 VScode 窗口半透明化(无毛玻璃效果,但是这个不影响性能)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Vibrancy&#34;&gt;Vibrancy&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;令&lt;strong&gt;VScode 毛玻璃型透明&lt;/strong&gt;,可选择透明度和非透明区域(注意这个插件比较影响性能)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;其他&#34;&gt;其他&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;h3 id=&#34;Power-Mode&#34;&gt;Power Mode&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;在码字时敲入文字后光标产生动画,很好看(但是会有点卡顿现象)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Chinese-Simplified-Language-Pack-for-Visual-Studio-Code&#34;&gt;Chinese (Simplified) Language Pack for Visual Studio Code&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;这个不解释,中国人看&lt;strong&gt;中国字&lt;/strong&gt;顺眼就对了&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;background&#34;&gt;background&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;可以让主窗口出来个偷看的小东方(默认情况下,可以自行修改),主要是&lt;strong&gt;养眼使用&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Material-Icon-Theme&#34;&gt;Material Icon Theme&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;侧边栏的资源管理器中的&lt;strong&gt;文件&lt;/strong&gt;们长出了&lt;strong&gt;头像&lt;/strong&gt;,更加好认了呢…&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;另外插件商店搜索 icon 也可以找到其他样式的图标包,看个人喜好了…&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Rainbow-Fart&#34;&gt;Rainbow Fart&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;不能算是美化吧…但只能放这了…打开浏览器一个辅助性页面,授权后在你码字触发某些关键字时会播放 “鼓励” 型话语,具体可以参考我的另一个项目&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;koroFileHeader&#34;&gt;koroFileHeader&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;在 new 文件时在文件头部加上作者,新建和更改日期,文件目录等信息(也可手动添加)&lt;br&gt;
另一个有趣功能是可以一键添加字符画!没啥用但挺有意思的…&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Live2D&#34;&gt;Live2D&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;在 VScode 里面添加一个 Live2D 看板娘&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Rainbow-String&#34;&gt;Rainbow String&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;使&amp;quot;&amp;quot;选中的字符串变成彩虹色,可以通过修改配置来使目标语言生效(比较影响性能)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Error-Lens&#34;&gt;Error Lens&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;使代码错误/警告在那一行尾部显示出来&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;码字推荐&#34;&gt;码字推荐&lt;/h2&gt;
&lt;h3 id=&#34;代码补全&#34;&gt;代码补全&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;h3 id=&#34;Visual-Studio-IntelliCode&#34;&gt;Visual Studio IntelliCode&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;VS 原配夫人,但是个人感觉,补全效果&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;TabNine &amp;gt; Kite &amp;gt; Visual Studio IntelliCode&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;TabNine&#34;&gt;TabNine&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;代码补全&lt;/strong&gt;的插件,不同的是它可以借助参考上下文,项目中的相似语句进行推荐补全(比语言自带的更强大,不冲突,这个是整句型补全,不嫌弃略卡的话实际很好用)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;是个&amp;quot;小巧&amp;quot;的(实际上打开 VScode 时占用内存 1G+,具体看项目大小了)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;可以补全纯文本&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Kite&#34;&gt;Kite&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;很出名的代码补全程序,需要安装外部程序(当然如果没安装的话,这个插件也会给你装上)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;补全效果很出色,但是个人用起来感觉并不如 TabNine 舒服~&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;其他-2&#34;&gt;其他&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;h3 id=&#34;Mover&#34;&gt;Mover&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;不会用 Vim,用这个也不错&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Bracket-Pair-Colorizer-2&#34;&gt;Bracket Pair Colorizer 2&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;只要码字时用到大中小括号,我就推荐搞上它,它可以让不同对括号标记&lt;strong&gt;不同颜色&lt;/strong&gt;来区分开,而且两配对的括号会&lt;strong&gt;标出缩进线&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;放心,这个版本 2 比 1 好&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Code-Runner&#34;&gt;Code Runner&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;在界面右上角出现三角形按钮,它允许在编译调试环境已经搭配好的情况下&lt;strong&gt;使 VScode 产生 IDE 的* 作用&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Markdown-All-in-One&#34;&gt;Markdown All in One&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;功能在名字中体现了,可以在 VScode 中&lt;strong&gt;打开/写/预览.md 文件&lt;/strong&gt;,VScode 版 typora&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Background-Phi-Colors&#34;&gt;Background Phi Colors&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;在缩进区域以及匹配选择产生不同颜色的&amp;quot;色块&amp;quot;,在缩进不标准时也会变色提醒,&lt;strong&gt;很实用!&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果你用过&lt;code&gt;indent-rainbow&lt;/code&gt;,那么我推荐的这个这个插件大概率可以更满足你!&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;h3 id=&#34;Better-Comments&#34;&gt;Better Comments&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;添加注释时在每行注释第一个字符写&amp;quot;!?*&amp;quot;等字符会该行让注释变色,有一定增强阅读效果&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;文章推荐&#34;&gt;文章推荐&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;有点老了,但是内容相当好.&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://blog.fundebug.com/2018/11/20/10-must-have-vs-code-extensions-for-javascript-developers/&#34;&gt;10 种 JavaScript 开发者必备的 VS Code 插件&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;
